OKToast={}function OKToast.toast(a,b)if b and Toast.showToastWithTime then Toast:showToastWithTime(a,b)else Toast:showToast(a)end end;function OKToast.success(a,b)if b and Toast.showSuccessWithTime then Toast:showSuccessWithTime(a,b)else Toast:showSuccess(a)end end;function OKToast.error(a,b)if isEmpty(a)or a=="\"\""then return end;if b and Toast.showErrorWithTime then Toast:showErrorWithTime(a,b)else Toast:showError(a)end end;function OKToast.showToastAtBottom(a)Toast:showToastAtBottom(a)end
